class HumidityDisplay implements Observer<number> {
  update(data: number): void {
    console.log(`Humidity display updated: ${data}%`);
  }
}

class Main {
  static main(): void {
    const subject = new SubjectImpl<number>();
    const weatherStation = new WeatherStation();
    weatherStation.setTemperature(22);
    const temperatureDisplay = new TemperatureDisplay();
    const humidityDisplay = new HumidityDisplay();
    subject.add(temperatureDisplay);
    subject.add(humidityDisplay);
    weatherStation.setTemperature(25);
    subject.remove(humidityDisplay);
    weatherStation.setTemperature(30);
  }
}
